-- ── Supermetrics ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Supermetrics is a marketing intelligence and data pipeline platform that automatically pulls data from more than 150 marketing, sales, and ad platforms into spreadsheets, BI tools, and data warehouses.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$49 euros/month (billed monthly), 39 euros/month billed annually$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Helsinki, Finland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Supermetrics Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Supermetrics review covering pricing, data connectors, BI integrations, and pros and cons for marketers who need automated reporting pipelines.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Supermetrics is a Finnish marketing intelligence and data pipeline company founded in 2013 by Mikael Thuneberg and headquartered in Helsinki, Finland. It automates the extraction of data from more than 150 advertising, marketing, sales, and analytics platforms (such as Google Ads, Facebook Ads, Google Analytics, and HubSpot) and delivers it into destinations like Google Sheets, Excel, Looker Studio, Power BI, Tableau, BigQuery, and Snowflake. The company serves roughly 200,000 organizations across 120 countries, ranging from solo marketers to large enterprises and agencies that need consolidated, automated reporting without manual exports. Supermetrics runs on a subscription model with four tiers: Starter (from 49 euros per month, one destination, three data sources, one user), Growth (from 199 euros per month), Pro (from 499 euros per month), and a custom-priced Enterprise plan with unlimited sources, data transformations, and a management API. Lower tiers include a bundle of AI credits and weekly, daily, or hourly refresh schedules depending on plan. The platform is bootstrapped-turned-VC-backed, having raised Series A funding in 2017 and Series B in 2020, and it acquired Dutch software company Relay42 to expand into a broader marketing intelligence platform. It is best suited for marketing agencies and in-house teams that rely on spreadsheet or BI-based reporting rather than custom data engineering.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a2099be2-0fe5-4bea-8970-af25479c0e1a';

