-- ── Superset ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Apache Superset is a free, open-source data exploration and visualization platform for building dashboards and charts on top of virtually any SQL-speaking database.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Apache Superset: Free Open-Source BI and Dashboard Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Apache Superset overview covering features, self-hosting, pricing, and how this open-source BI platform compares to managed alternatives like Preset.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Apache Superset is a free, open-source data exploration and visualization platform originally created by Maxime Beauchemin at Airbnb during a hackathon in 2015, when it was named Caravel. It was open sourced shortly after, entered the Apache Software Foundation Incubator in 2017, and graduated to a top-level Apache project in 2021. Superset is licensed under Apache License 2.0 and is built with Python and TypeScript. It lets users build charts and dashboards on top of SQL-speaking databases and data warehouses at scale, with support for enterprise authentication methods like OAuth, OpenID, and LDAP, a lightweight semantic layer, and a large library of visualization types including integration with Apache ECharts. Because it is a community-governed open-source project rather than a company, there is no vendor subscription fee to self-host Superset; organizations run it on their own infrastructure for free and only incur their own hosting costs. Preset, a commercial company founded by Beauchemin and backed by Andreessen Horowitz, Fathom Capital, and Redpoint Ventures, offers a managed cloud version of Superset for teams that prefer not to operate it themselves. Superset is best suited for data and engineering teams that want a self-hosted, SQL-native BI tool without per-seat licensing costs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0c430e24-d037-4fa9-9d90-6b483daf4467';

