-- ── SuperTokens ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SuperTokens is an open-source user authentication platform that offers prebuilt login flows, session management, and either self-hosted or managed cloud deployment.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, or cloud usage under 5,000 monthly active users)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SuperTokens Review: Open-Source Authentication Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$SuperTokens overview covering open-source authentication features, self-hosted vs cloud pricing, and how it compares to Auth0 and Firebase Auth.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SuperTokens is an open-source user authentication platform founded in 2019 by Rishabh Poddar and Advait Ruia, headquartered in San Francisco, California, with an additional office in Mumbai, India. It is positioned as an open-source alternative to proprietary identity providers such as Auth0, Firebase Auth, and AWS Cognito. SuperTokens offers email and password login, passwordless login via magic links or OTP, and social and OAuth 2.0 login with providers like Google, GitHub, and Facebook, along with session management, role-based access control, a user management dashboard, and multi-factor authentication. It can be self-hosted for free at any scale using the open-source core, or run through SuperTokens' managed cloud service, which is free for up to 5,000 monthly active users and then billed at 0.02 dollars per MAU with a 100 dollar monthly minimum once that threshold is crossed. Paid add-ons include multi-factor authentication, account linking, a per-seat dashboard user fee, multi-tenancy, and machine-to-machine authentication, most priced separately from the core MAU fee. The company is backed by Y Combinator and reported roughly 5 million dollars in revenue with a small team. SuperTokens is aimed at engineering teams that want full control over authentication infrastructure and user data without vendor lock-in.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3a5bd012-2f3f-4dff-ab18-daad2501a4b0';

