-- ── SupportBee ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SupportBee is an email-first help desk platform that gives small teams a shared inbox, knowledge base, and customer portal for managing support tickets collaboratively.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$17/seat/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SupportBee Review: Help Desk Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$SupportBee review covering its shared inbox, knowledge base, customer portal, pricing plans, and pros and cons for small support teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SupportBee is an email-first help desk platform built around a shared inbox rather than a traditional complex ticketing dashboard, aimed at small teams that handle customer support primarily through email. It was founded by Hana Mohan and Nithya Rajaram in the early 2010s. Its core features include a shared inbox for collaborative email handling, a knowledge base and customer portal, saved reply snippets, customer satisfaction ratings, filters, basic and enterprise-tier integrations, API access, and unlimited email inboxes and tickets on every plan with no per-ticket charges. SupportBee is priced on two subscription tiers: Startup at 17 dollars per seat per month billed annually (20 dollars per seat per month billed monthly), and Enterprise at 21 dollars per seat per month billed annually (25 dollars per seat per month billed monthly), with Enterprise adding the customer portal, business hours, enterprise integrations, and audit log and data history. Both plans include a 14-day free trial and can be cancelled anytime without penalty. SupportBee positions itself against more complex help desk suites by emphasizing simplicity, transparent per-seat pricing, and a familiar email-based workflow, making it a fit for small support teams and startups that find larger platforms like Zendesk or Freshdesk overbuilt for their needs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '56724599-1872-4e62-b903-ed19a3916f2f';

