-- ── SuprSend ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SuprSend is a notification infrastructure platform that lets developers and product teams design, send, and manage multi-channel notifications through a single API.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (up to 10,000 notifications/month)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SuprSend Review: Notification API Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$SuprSend review covering its notification infrastructure API, multi-channel workflows, pricing plans, and pros and cons for product and engineering teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SuprSend is a notification infrastructure platform founded in January 2022 by Nikita Navral and Gaurav Varma, headquartered in San Francisco, California. It gives engineering and product teams a single API and workflow builder to design, trigger, and manage transactional and marketing-style notifications across channels including email, SMS, WhatsApp, mobile push, web push, Slack, Microsoft Teams, in-app inbox, and webhooks, without building and maintaining separate integrations per channel. Key capabilities include a no-code workflow builder, a customizable in-app notification inbox with drop-in React components, template management with versioning and A/B testing, batching and digest logic, timezone-aware sending, user preference centers, and AI features such as an MCP server and agent SDK. SuprSend prices on notification and monthly tracked user volume rather than API request count: a Free plan covers up to 10,000 notifications per month, Essentials starts around 100 to 110 dollars per month for 50,000 notifications, Business starts around 250 to 275 dollars per month, and Enterprise is custom-priced with features like multi-tenant data modeling, SAML SSO, HIPAA compliance, dedicated infrastructure, and a Bring Your Own Cloud deployment option. The company has raised seed funding, including a 1 million dollar round led by BoldCap, and serves customers such as CrazyGames, Teachmint, and Freightify. SuprSend is best suited for product and engineering teams that want to centralize multi-channel notification logic instead of managing it themselves.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a57f6aeb-72fe-474e-8368-01db35053063';

