-- ── Surfer ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Surfer is a lightweight, open-source static file server packaged for Cloudron, letting self-hosters serve static websites and share files through a web interface, CLI, or WebDAV.$q$, short_description),
  pricing_model = COALESCE($q$free/open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Surfer (Cloudron): Static Site and File Hosting Overview$q$, seo_title),
  seo_meta_description = COALESCE($q$Overview of Surfer, the open-source static file server app for Cloudron, covering its features, deployment model, and how it differs from Surfer SEO.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Surfer is an open-source static file server packaged as an app for the Cloudron self-hosting platform, maintained in the Cloudron GitLab and GitHub organizations. It is not related to Surfer SEO, the content optimization SaaS company; Surfer the Cloudron app is instead a simple tool for serving static websites and sharing files from a self-hosted server. It provides a web-based admin interface (typically available at a slash underscore admin path on the app domain), a command-line tool for uploading files from local folders, and WebDAV support so files can be mounted and managed directly through a desktop file manager on Windows, Mac, or Linux. Additional capabilities include automatic serving of index.html or index.htm files, optional public directory listing, custom 404 error pages, and three access control modes covering fully public access, password protection, or Cloudron user login. Because it has a very low resource footprint, the recommended deployment pattern is to run one Surfer instance per domain so that separate static sites remain isolated from each other. As an open-source, self-hosted Cloudron package rather than a commercial company, Surfer has no pricing tiers, no publicly documented founding date, headquarters, or employee count, and is used primarily by individuals and small teams already running a Cloudron server who need simple static site or file hosting without paying for a separate managed service.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7790e8ea-c240-4ee6-9b40-8da31a143d62';

