-- ── Surfer SEO ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Surfer SEO is a cloud-based content optimization platform that combines SERP analysis, an AI content editor, keyword research, and AI search visibility tracking to help teams create pages that rank.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$49 euros/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Wroclaw, Poland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Surfer SEO Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Surfer SEO review covering content optimization features, AI search tracking, pricing tiers, and pros and cons for SEO teams and content creators.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Surfer SEO is a cloud-based content optimization platform founded in 2017 by Michal Suski and Tomasz Niezgoda and headquartered in Wroclaw, Poland. It is not related to the Cloudron Surfer static file server despite sharing a short name. In January 2025 Surfer SEO was acquired by Groupe Positive, a European SaaS provider based in Lille, France, and the product is now marketed under the name Positive Surfer. Surfer SEO analyzes top-ranking search results and provides data-driven content guidelines, keyword research, an AI writing and optimization editor, a plagiarism checker, an AI humanizer, content audits, topical mapping, and internal linking recommendations, alongside newer AI search visibility tracking across ChatGPT, Perplexity, Google AI features, and Gemini. It integrates with WordPress, Google Docs, Contentful, and Zapier. As of 2026, pricing runs on five tiers billed annually: Discovery at 49 euros per month, Standard at 99 euros per month, Pro at 182 euros per month, Peace of Mind at 299 euros per month, and a custom-priced Enterprise tier from roughly 999 euros per month with SSO and white-label options. The company reports being used by more than 150,000 content creators, SEO professionals, and agencies worldwide, and every plan includes a 7-day money-back guarantee. Surfer SEO is best suited for content teams, SEO agencies, and marketers who want quantitative, SERP-based guidance for writing and optimizing pages that rank in both traditional and AI-powered search.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a009a42b-b701-46b1-bc27-3bc5f232d1f9';

