INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$150-plus data connectors$q$, $q$Pre-built connectors for major ad platforms, analytics tools, CRMs, and social channels remove the need for custom API integrations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Spreadsheet integrations$q$, $q$Native add-ons for Google Sheets and Excel let marketers pull live campaign data straight into familiar reporting templates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$BI tool destinations$q$, $q$Direct integrations with Looker Studio, Power BI, and Tableau support building automated executive dashboards.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Data warehouse loading$q$, $q$Data can be piped into BigQuery, Snowflake, and Amazon Redshift for teams that centralize marketing data alongside other business data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Scheduled refreshes$q$, $q$Refresh cadence ranges from weekly on the Starter plan to hourly on Pro, keeping reports current without manual pulls.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Custom data import$q$, $q$Offline, CRM, or spreadsheet-based data can be blended with platform data for a fuller view of marketing performance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Management API$q$, $q$Enterprise customers can programmatically manage connections and configurations across many client or brand accounts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$AI credits$q$, $q$Bundled AI credits power natural-language data queries and automated reporting assistance within the platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Very broad library of ready-made connectors covering most major marketing and ad platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Lets non-technical marketers build automated reports without SQL or custom code$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Works inside tools teams already use, including Google Sheets, Excel, and popular BI platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Scales from a single small-business user up to enterprise data warehouse pipelines$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Established vendor with roughly 200,000 customers and a long operating history since 2013$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$As of 2026 Supermetrics only offers annual billing on some plans, reducing short-term flexibility$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Costs rise quickly as more data sources, users, or destinations are added$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$No permanently free plan for ongoing use, only trial access$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Complex multi-source setups may still need someone with data modeling experience$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Some advanced features and higher refresh frequencies are gated behind the pricier Pro and Enterprise tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$What is Supermetrics used for$q$, $q$Supermetrics is used to automatically collect marketing, advertising, and sales data from many platforms and deliver it into spreadsheets, BI dashboards, or data warehouses for reporting and analysis.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$How much does Supermetrics cost$q$, $q$Plans start at 49 euros per month for the Starter tier, with Growth at 199 euros per month and Pro at 499 euros per month; Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Does Supermetrics offer a free trial$q$, $q$Supermetrics has offered free trials on its paid plans in the past; current trial availability should be confirmed on the official pricing page since terms change over time.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$What data sources does Supermetrics support$q$, $q$Supermetrics supports more than 150 data sources including Google Ads, Meta Ads, LinkedIn Ads, TikTok Ads, Google Analytics, and HubSpot, among many others.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Can Supermetrics send data to Google Sheets$q$, $q$Yes, Supermetrics offers native add-ons for Google Sheets and Excel that pull live data directly into spreadsheet reports.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Is Supermetrics suitable for data warehouses$q$, $q$Yes, higher-tier plans support loading data into warehouses such as BigQuery, Snowflake, and Amazon Redshift.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Who founded Supermetrics$q$, $q$Supermetrics was founded by Mikael Thuneberg, who formally established the company in Helsinki, Finland in 2013 after building early scripts connecting Google Analytics to Excel.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Is Supermetrics good for marketing agencies$q$, $q$Yes, agencies commonly use Supermetrics to consolidate reporting across multiple client accounts, though larger agencies typically need the Growth or Pro tier to cover enough data sources and users.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Agency client reporting$q$, $q$Marketing agencies use Supermetrics to pull performance data from every client ad account into standardized dashboards or spreadsheets on an automated schedule.$q$, $q$Digital marketing and media agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$In-house marketing dashboards$q$, $q$In-house marketing teams connect their ad and analytics accounts to build recurring executive dashboards without manual data pulls.$q$, $q$In-house marketing and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Marketing data warehousing$q$, $q$Data and analytics teams use Supermetrics to load raw marketing data into a central warehouse where it can be joined with sales and product data for deeper analysis.$q$, $q$Data engineers and analytics teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Starter$q$, $q$49 euros/month (39 euros/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["1 core destination","3 data sources","1 user","4,000 AI credits","Weekly data refreshes","Dashboards","SSO","API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Growth$q$, $q$199 euros/month (159 euros/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["1 core destination","7 data sources","2 users","12,000 AI credits","Daily refreshes","Custom data import (1 configuration)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Pro$q$, $q$499 euros/month (399 euros/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["1 core destination","10 data sources","3 users","18,000 AI credits","Hourly refreshes","Supermetrics Storage Basic add-on option"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Enterprise$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["All core and data warehouse destinations","Custom users and sources","On-demand refreshes","Data transformations","Full storage access","Management API","Support for multiple teams"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$overview$q$, $q$What Is Supermetrics$q$, 2, ARRAY[$q$Supermetrics is a marketing intelligence and data pipeline platform that connects marketing, sales, and advertising platforms to the spreadsheets, dashboards, and data warehouses teams already use. It started in 2009 when founder Mikael Thuneberg wrote a script to pull Google Analytics data into Microsoft Excel, and the company was formally founded in Helsinki, Finland in 2013.$q$, $q$Today Supermetrics offers more than 150 pre-built connectors covering platforms like Google Ads, Meta Ads, LinkedIn Ads, TikTok Ads, Google Analytics, and HubSpot, and it moves that data into destinations such as Google Sheets, Excel, Looker Studio, Power BI, Tableau, BigQuery, Snowflake, and Amazon Redshift. Roughly 200,000 companies in around 120 countries use the product for automated marketing reporting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of Supermetrics is its connector library, which lets non-technical marketers pull raw campaign and analytics data on a schedule without writing SQL or building custom integrations. Data can refresh weekly, daily, or hourly depending on plan, and results land directly in spreadsheets, BI dashboards, or a data warehouse.$q$, $q$Beyond raw extraction, Supermetrics offers dashboard templates, a management API for governing multiple accounts, custom data import for blending offline or CRM data with platform data, and AI credits that power features like natural-language querying and automated insights across connected accounts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Supermetrics is sold on four subscription tiers. Starter begins at 49 euros per month (39 euros per month billed annually) and includes one destination, three data sources, one user, and weekly refreshes. Growth starts at 199 euros per month with seven data sources, two users, and daily refreshes. Pro starts at 499 euros per month with ten data sources, three users, and hourly refreshes. Enterprise is custom-priced and adds unlimited sources and users, data transformations, full warehouse storage access, and support for multiple teams.$q$, $q$There is no permanently free tier, and pricing scales with the number of data sources, users, and refresh frequency selected, so agencies managing many client accounts typically land on the Growth or Pro tier rather than Starter.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$No-code chart builder$q$, $q$Users can create dozens of chart types through a visual interface without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$SQL Lab$q$, $q$A built-in SQL editor lets analysts write and run queries directly against connected databases for ad hoc exploration.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Broad database support$q$, $q$Superset connects to most SQL-speaking databases and warehouses, including Postgres, MySQL, BigQuery, Snowflake, and Redshift.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Semantic layer$q$, $q$A lightweight metrics layer lets teams define reusable calculations and dimensions across dashboards.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Enterprise authentication$q$, $q$Built-in support for OAuth, OpenID Connect, and LDAP enables integration with existing identity systems.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Row-level security$q$, $q$Access rules can restrict which rows or datasets individual users or roles are allowed to see.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Visualization plugins$q$, $q$A plugin architecture and Apache ECharts integration allow teams to extend the built-in chart library.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Dashboard sharing and embedding$q$, $q$Dashboards can be shared internally or embedded into other applications for wider distribution.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Completely free and open source with no per-seat licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Backed by the Apache Software Foundation with an active open-source community$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Connects to a very wide range of SQL databases and data warehouses$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Highly extensible through plugins and a semantic layer$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$No vendor lock-in since the project and its source code are fully open$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Self-hosting requires engineering effort to deploy, secure, and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$No official vendor support channel for the free open-source version$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Setup and configuration are more technical than fully managed BI tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Feature velocity and documentation quality can vary release to release since it is community-driven$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Teams wanting a hosted, supported version must adopt a separate commercial product like Preset$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Is Apache Superset free$q$, $q$Yes, Apache Superset is free and open source under the Apache License 2.0; you only pay for the infrastructure you host it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Who created Apache Superset$q$, $q$Superset was created by Maxime Beauchemin at Airbnb in 2015 as a hackathon project originally named Caravel.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$What is the difference between Superset and Preset$q$, $q$Superset is the free, open-source project governed by the Apache Software Foundation, while Preset is a separate commercial company that sells a managed, hosted version of Superset as a paid SaaS product.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$What databases does Superset support$q$, $q$Superset connects to most SQL-speaking databases and data warehouses, including Postgres, MySQL, BigQuery, Snowflake, and Amazon Redshift, among many others.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Can Superset handle large-scale data$q$, $q$Yes, Superset is designed to handle data exploration and visualization at large scale, including petabyte-scale datasets when connected to an appropriate warehouse.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Does Superset support single sign-on$q$, $q$Yes, Superset supports enterprise authentication methods including OAuth, OpenID Connect, and LDAP.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Is Superset a top-level Apache project$q$, $q$Yes, Superset graduated from the Apache Incubator and became a top-level Apache Software Foundation project in 2021.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Do I need coding skills to use Superset$q$, $q$Basic dashboard building can be done through the no-code chart builder, but self-hosting, advanced SQL queries, and custom visualizations typically require technical skills.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Self-hosted BI for engineering-led teams$q$, $q$Data and platform engineering teams deploy Superset internally to give analysts and stakeholders dashboards without paying per-seat BI licensing fees.$q$, $q$Data engineering and analytics teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$SQL-native ad hoc analysis$q$, $q$Analysts use SQL Lab within Superset to explore warehouse data directly and turn queries into shareable charts and dashboards.$q$, $q$Data analysts and BI developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Embedded analytics in internal tools$q$, $q$Engineering teams embed Superset dashboards inside internal applications or customer-facing products to surface data without building custom visualization tooling.$q$, $q$Product and engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$Open Source (self-hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full dashboarding and chart-building functionality","SQL Lab query editor","Broad database connector support","Community support only","Apache License 2.0"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$overview$q$, $q$What Is Superset$q$, 2, ARRAY[$q$Apache Superset is an open-source data exploration and visualization platform capable of handling data at large scale. It began as a three-day hackathon project called Caravel built by Maxime Beauchemin at Airbnb in 2015, was open sourced soon after, and entered the Apache Software Foundation Incubator in 2017 before becoming a fully independent top-level Apache project in 2021.$q$, $q$Unlike closed-source BI tools sold as a subscription, Superset is free to download, self-host, and modify under the Apache License 2.0. It is written primarily in Python and TypeScript and connects to virtually any SQL-speaking database or data warehouse, making it popular with engineering-led data teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Superset supports building interactive dashboards and charts using a no-code chart builder or a SQL Lab query editor for more advanced analysis. It ships with dozens of visualization types and integrates with Apache ECharts, plus a plugin system for adding custom visualizations.$q$, $q$It includes a lightweight semantic layer for defining metrics and dimensions once and reusing them across charts, and it supports enterprise-grade authentication through OAuth, OpenID Connect, and LDAP, along with row-level security for controlling what data different users can see.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Superset itself is entirely free and open source; there is no license fee for self-hosting it on your own servers or cloud infrastructure, only the underlying compute and storage costs. Organizations that want a managed, hosted version without operating the infrastructure themselves can instead use Preset, a commercial SaaS built on Superset by its original creator, which is priced separately from the open-source project.$q$, $q$Because pricing for Preset's managed offering is set by a separate company and changes over time, teams evaluating a hosted option should check Preset's own pricing page rather than assuming it matches any figures published for the open-source project.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c430e24-d037-4fa9-9d90-6b483daf4467', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Email and password login$q$, $q$Standard credential-based authentication with built-in email verification and password reset flows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Passwordless login$q$, $q$Magic link and one-time password login via SMS or email removes the need for users to manage passwords.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Social and OAuth login$q$, $q$Prebuilt integrations support login with Google, GitHub, Facebook, and other OAuth 2.0 providers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Session management$q$, $q$Secure, rotating session tokens are handled automatically to protect against common session attacks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Multi-factor authentication$q$, $q$An optional MFA add-on adds an extra verification step for higher-security applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$User management dashboard$q$, $q$A built-in admin dashboard lets teams view, search, and manage user accounts without custom tooling.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Role-based access control$q$, $q$RBAC lets teams assign permissions and roles to users directly within the authentication layer.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Self-hosted or managed cloud$q$, $q$Teams can run SuperTokens entirely on their own infrastructure or offload hosting to the managed cloud service.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Open-source core is free to self-host at unlimited scale with full data ownership$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Cloud plan has a generous free tier of up to 5,000 monthly active users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Broad SDK coverage across Node.js, Python, Go, React, and React Native$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Avoids vendor lock-in compared to closed-source identity providers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Backed by Y Combinator with active development and community support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Self-hosting requires engineering time to deploy, secure, and maintain infrastructure$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Several useful features like multi-factor authentication and account linking are paid add-ons rather than included$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Multi-tenancy and machine-to-machine auth pricing require contacting sales rather than transparent self-serve pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Smaller team and community than large incumbents like Auth0 may mean slower support response for edge cases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Dashboard user pricing at 20 dollars per user per month can add up for larger internal teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Is SuperTokens free$q$, $q$Yes, the open-source core is free to self-host at any scale, and the managed cloud version is free for up to 5,000 monthly active users.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Who founded SuperTokens$q$, $q$SuperTokens was founded in 2019 by Rishabh Poddar and Advait Ruia and is headquartered in San Francisco, California.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$How does SuperTokens pricing work$q$, $q$Self-hosted use is free at unlimited scale; the managed cloud service charges 0.02 dollars per monthly active user above a 5,000 MAU free tier, with a 100 dollar monthly minimum once billing starts, plus optional paid add-ons.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$What login methods does SuperTokens support$q$, $q$SuperTokens supports email and password login, passwordless login via magic link or OTP, and social and OAuth 2.0 login with providers like Google, GitHub, and Facebook.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Is SuperTokens an alternative to Auth0$q$, $q$Yes, SuperTokens is commonly positioned as an open-source alternative to Auth0, Firebase Auth, and AWS Cognito.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Which programming languages does SuperTokens support$q$, $q$Backend SDKs cover Node.js, Python, and Go, with frontend support for vanilla JavaScript, React, and React Native.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Can SuperTokens be self-hosted$q$, $q$Yes, the open-source core can be self-hosted on a team's own infrastructure and database at no licensing cost.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Does SuperTokens support multi-factor authentication$q$, $q$Yes, multi-factor authentication is available as a paid add-on priced per monthly active user.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Custom authentication for SaaS products$q$, $q$Engineering teams building a SaaS product use SuperTokens to add login, session management, and MFA without building it from scratch or fully outsourcing to a closed vendor.$q$, $q$Startup and SaaS engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Data-sovereign self-hosted auth$q$, $q$Companies with strict data residency or compliance requirements self-host SuperTokens so user credentials never leave their own infrastructure.$q$, $q$Regulated industries and enterprises with compliance needs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Replacing legacy or expensive identity providers$q$, $q$Teams migrating off costly proprietary identity platforms use SuperTokens to reduce per-user authentication costs while keeping similar functionality.$q$, $q$Engineering teams optimizing infrastructure spend$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Self-Hosted Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Unlimited users","Full open-source feature set","Deploy on your own infrastructure","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Cloud$q$, $q$Free under 5,000 MAU, then 0.02 dollars per MAU (100 dollar monthly minimum)$q$, $q$monthly$q$, NULL, $q$["Managed hosting and scaling","Same core authentication features as self-hosted","SOC 2 compliance","Optional paid add-ons"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$Add-ons$q$, $q$Varies (from 0.005 dollars per MAU)$q$, $q$monthly$q$, NULL, $q$["Multi-factor authentication","Account linking","Dashboard users (20 dollars/user/month, 3 free)","Multi-tenancy (custom quote)","Machine-to-machine authentication (custom quote)"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$overview$q$, $q$What Is SuperTokens$q$, 2, ARRAY[$q$SuperTokens is an open-source authentication and session management platform built as an alternative to closed-source identity providers. Founded in 2019 by Rishabh Poddar and Advait Ruia and headquartered in San Francisco with a Mumbai office, the company positions its product as a way for engineering teams to own their authentication stack instead of depending entirely on a third-party vendor.$q$, $q$The platform can be deployed in two ways: fully self-hosted on a team's own infrastructure using the open-source core at no cost, or run through SuperTokens' managed cloud service, which handles hosting, scaling, and reliability for a usage-based fee.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core authentication methods include email and password login, passwordless login through magic links or one-time codes sent by SMS or email, and social and OAuth 2.0 login with providers such as Google, GitHub, and Facebook. The platform also handles email verification and password reset flows out of the box.$q$, $q$Beyond login itself, SuperTokens provides session management, a user management dashboard, role-based access control, multi-factor authentication, and prebuilt sign-up and sign-in UI components, along with hooks and overrides that let developers customize behavior at the code level. Backend SDKs are available for Node.js, Python, and Go, with frontend support for vanilla JavaScript, React, and React Native.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting the open-source core is free at any scale, with no cap on the number of users, since teams run it on their own database and infrastructure. SuperTokens' managed cloud offering is free for up to 5,000 monthly active users, then billed at 0.02 dollars per MAU with a 100 dollar monthly minimum once that threshold is exceeded.$q$, $q$Paid add-ons apply on top of the base plan for both self-hosted and cloud deployments, including multi-factor authentication at 0.01 dollars per MAU, account linking at 0.005 dollars per MAU, and dashboard users at 20 dollars per user per month with three free. Multi-tenancy and machine-to-machine authentication are priced through custom sales quotes.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3a5bd012-2f3f-4dff-ab18-daad2501a4b0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Shared inbox$q$, $q$Multiple agents can view, discuss, and respond to the same customer emails from a single collaborative inbox.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Reply snippets$q$, $q$Saved canned responses speed up replies to frequently asked questions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Knowledge base$q$, $q$A self-service knowledge base lets customers find answers without opening a ticket.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Customer portal$q$, $q$On the Enterprise plan, customers can log in to track the status of their own support tickets.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Customer satisfaction ratings$q$, $q$Built-in CSAT surveys let teams measure support quality directly from resolved tickets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Filters and routing$q$, $q$Filters help organize and route incoming support emails to the right agents or inboxes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$API access$q$, $q$All plans include API access for integrating SupportBee with other internal tools and workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Unlimited inboxes and tickets$q$, $q$Every plan supports unlimited email inboxes and ticket volume with no per-ticket charges.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Simple, email-first workflow that is easy for small teams to adopt quickly$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Transparent per-seat pricing with no hidden per-ticket fees$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Unlimited tickets and inboxes included on every plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$14-day free trial and no-penalty cancellation lower the risk of trying it$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Lighter weight and less complex to configure than large enterprise help desk suites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Fewer advanced automation and workflow features compared to larger platforms like Zendesk or Freshdesk$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Customer portal is only available on the higher-priced Enterprise plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Public information on company headquarters and team size is limited and inconsistent across sources$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Smaller integration ecosystem than category leaders$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$May not scale well for large support organizations with complex routing needs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$What is SupportBee used for$q$, $q$SupportBee is a help desk platform used by small teams to manage customer support email collaboratively through a shared inbox, knowledge base, and customer portal.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$How much does SupportBee cost$q$, $q$SupportBee costs 17 dollars per seat per month billed annually on the Startup plan, and 21 dollars per seat per month billed annually on the Enterprise plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Does SupportBee offer a free trial$q$, $q$Yes, both SupportBee plans include a 14-day free trial.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Does SupportBee charge per ticket$q$, $q$No, all plans include unlimited email inboxes and tickets with no per-ticket charges.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$What is the difference between SupportBee Startup and Enterprise plans$q$, $q$The Enterprise plan adds a customer portal, business hours configuration, enterprise-grade integrations, and audit log and data history on top of everything in the Startup plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Who founded SupportBee$q$, $q$SupportBee was co-founded by Hana Mohan and Nithya Rajaram.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Can I cancel SupportBee anytime$q$, $q$Yes, SupportBee subscriptions can be cancelled at any time without penalty.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Is SupportBee good for small businesses$q$, $q$Yes, SupportBee is designed for small support teams that want a simple, email-based help desk without the complexity of larger enterprise platforms.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Small team email support$q$, $q$Small businesses use SupportBee's shared inbox to manage customer emails collaboratively without juggling separate personal inboxes.$q$, $q$Small businesses and startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Self-service knowledge base$q$, $q$Support teams publish a knowledge base alongside their inbox so customers can resolve common questions without contacting an agent.$q$, $q$Customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Customer-facing ticket tracking$q$, $q$Enterprise-plan customers give their own clients a portal to check ticket status, reducing repeat status-check emails.$q$, $q$Businesses with external customer-facing support$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Startup$q$, $q$$17/seat/month billed annually ($20/seat/month billed monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Shared inbox","Snippets","1 knowledge base and 1 team","Filters","Basic integrations","API access","Unlimited email inboxes and tickets","Customer satisfaction ratings","Customer management","Audit trails"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$Enterprise$q$, $q$$21/seat/month billed annually ($25/seat/month billed monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Startup","Enterprise integrations","Business hours","Customer portal software","Audit log and data history","Portal access for customer groups"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$overview$q$, $q$What Is SupportBee$q$, 2, ARRAY[$q$SupportBee is a help desk platform built around a shared inbox model, letting small teams manage customer support email collaboratively without the complexity of a large enterprise ticketing suite. It was co-founded by Hana Mohan and Nithya Rajaram in the early 2010s.$q$, $q$Rather than forcing every conversation through rigid ticket workflows, SupportBee keeps the experience close to email while adding collaboration features like internal notes, saved reply snippets, and a knowledge base, which appeals to small teams that want simplicity over configurability.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SupportBee's shared inbox lets multiple agents see and respond to the same set of customer emails, with internal discussion threads for behind-the-scenes collaboration before replying to a customer. Snippets store canned responses for common questions, and filters help route or organize incoming messages.$q$, $q$The Enterprise plan adds a customer-facing portal where customers can view and track their own tickets, along with business hours configuration, deeper third-party integrations, and audit log and data history for compliance-minded teams. All plans include unlimited email inboxes and tickets with no per-ticket charges, plus API access for building custom workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56724599-1872-4e62-b903-ed19a3916f2f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SupportBee offers two plans, both billed per seat. The Startup plan costs 17 dollars per seat per month when billed annually, or 20 dollars per seat per month billed monthly, and includes the shared inbox, snippets, one knowledge base, filters, basic integrations, and API access. The Enterprise plan costs 21 dollars per seat per month billed annually, or 25 dollars per seat per month billed monthly, adding the customer portal, business hours, enterprise integrations, and audit log and data history.$q$, $q$Both plans include a 14-day free trial, unlimited tickets and inboxes with no hidden per-ticket fees, and subscriptions can be cancelled at any time without penalty.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Single API for all channels$q$, $q$One API call can trigger notifications across email, SMS, WhatsApp, push, Slack, Teams, and in-app inbox.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$No-code workflow builder$q$, $q$Product managers can configure multi-step notification workflows and branching logic without writing code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$In-app notification inbox$q$, $q$A customizable, real-time in-app inbox ships with drop-in React components or a headless API for custom UI.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Template engine$q$, $q$A WYSIWYG editor supports template versioning, A/B testing, and multi-language content.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Batching and digest$q$, $q$Notifications can be grouped into digests to avoid overwhelming users with individual alerts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$User preference center$q$, $q$End users can control which notification types and channels they receive through a built-in preference center.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Multi-tenant data modeling$q$, $q$SaaS platforms serving many customer organizations can model notification data per tenant.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$AI-assisted workflows$q$, $q$An MCP server, agent SDK, and AI co-pilot help teams build and automate notification workflows faster.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Free plan covers up to 10,000 notifications per month with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Single API and workflow builder cover essentially every major notification channel$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$In-app inbox ships with ready-made React components to speed up integration$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Enterprise tier supports HIPAA compliance and self-hosted or Bring Your Own Cloud deployment$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Backed by seed funding and used by recognizable customers like CrazyGames and Teachmint$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$As a company founded in 2022 with a small team, its long-term track record is shorter than legacy notification vendors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Advanced features like batching, digests, and data modeling for objects are gated behind the Business plan and above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Enterprise features such as SSO and HIPAA compliance require a custom quote rather than transparent pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Pricing model based on notification and tracked-user volume requires forecasting usage to avoid overage costs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Smaller ecosystem and community compared to older, larger notification platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$What is SuprSend used for$q$, $q$SuprSend is used by product and engineering teams to design, send, and manage transactional and engagement notifications across multiple channels through a single API.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Is SuprSend free$q$, $q$Yes, SuprSend offers a free plan covering up to 10,000 notifications per month with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$How much does SuprSend cost$q$, $q$Paid plans start at roughly 100 to 110 dollars per month for the Essentials tier covering 50,000 notifications, with Business and Enterprise tiers priced higher for additional volume and features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$What channels does SuprSend support$q$, $q$SuprSend supports email, SMS, WhatsApp, mobile push, web push, Slack, Microsoft Teams, an in-app inbox, and webhooks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Who founded SuprSend$q$, $q$SuprSend was founded in January 2022 by Nikita Navral and Gaurav Varma and is headquartered in San Francisco, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Does SuprSend support self-hosted deployment$q$, $q$Yes, the Enterprise plan offers self-hosted and Bring Your Own Cloud deployment options for teams with strict data residency needs.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Does SuprSend charge based on API requests$q$, $q$No, SuprSend charges based on notification volume and monthly tracked users rather than the number of API requests made.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Is SuprSend suitable for multi-tenant SaaS products$q$, $q$Yes, SuprSend supports multi-tenant data modeling, which is useful for SaaS platforms managing notifications across many customer organizations.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Product notification infrastructure$q$, $q$Engineering teams replace custom-built email, SMS, and push integrations with SuprSend's single API to reduce maintenance overhead.$q$, $q$Product engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$In-app notification center$q$, $q$Product teams add a real-time in-app inbox to their web or mobile app using SuprSend's prebuilt components instead of building one from scratch.$q$, $q$Product and frontend teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Multi-tenant SaaS notifications$q$, $q$B2B SaaS companies use SuprSend's multi-tenant data modeling to manage distinct notification preferences and branding across many customer organizations.$q$, $q$B2B SaaS platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["10,000 notifications/month","Unlimited channels","Multiple step workflows","Branching and conditions","Lists and broadcasts","Unlimited team members"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Essentials$q$, $q$$110/month ($100/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["50,000 notifications/month","$2 per 1,000 additional notifications","Removed SuprSend branding from in-app feed","Translation (i18n) support","Send in recipient's timezone"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Business$q$, $q$$275/month ($250/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["50,000 notifications/month base","$5 per 1,000 additional notifications","Batching and digest","User preferences","Data modeling for objects","Sync logs to Segment or data warehouse"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Multi-tenant data modeling","Audit trail and role-based access control","SAML 2.0 SSO","HIPAA/BAA compliance","Dedicated infrastructure","Self-hosted or Bring Your Own Cloud deployment"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$overview$q$, $q$What Is SuprSend$q$, 2, ARRAY[$q$SuprSend is a notification infrastructure platform founded in January 2022 by Nikita Navral and Gaurav Varma and headquartered in San Francisco, California. It is built for product and engineering teams that need to send transactional and engagement notifications across many channels without maintaining a separate integration for each one.$q$, $q$Instead of writing custom logic for email, SMS, push, and chat notifications individually, teams design a notification once inside SuprSend and route it to whichever channels are relevant per user, using a single API and a shared set of templates and workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SuprSend supports email, SMS, WhatsApp, mobile push, web push, Slack, Microsoft Teams, an in-app notification inbox, and webhooks from one platform. Its workflow builder lets non-technical product managers configure multi-step notification logic, branching, and conditions outside of code, while a WYSIWYG template engine supports versioning, A/B testing, and internationalization.$q$, $q$More advanced functionality includes batching and digest delivery, timezone-aware sending, a user preference center for granular opt-in and opt-out control, smart channel routing, and multi-tenant data modeling for SaaS platforms serving many customer organizations. The platform also offers AI features such as an MCP server, an agent SDK, and an AI co-pilot for building workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a57f6aeb-72fe-474e-8368-01db35053063', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SuprSend prices plans by notification volume and monthly tracked users rather than by API request count. The Free plan covers up to 10,000 notifications per month with no credit card required. The Essentials plan starts at roughly 100 to 110 dollars per month for 50,000 notifications, with overage priced per additional thousand notifications. The Business plan starts at roughly 250 to 275 dollars per month and adds batching and digest, user preferences, and data modeling for objects.$q$, $q$The Enterprise plan is custom-priced and adds multi-tenant data modeling, audit trail and role-based access control, SAML 2.0 single sign-on, HIPAA and BAA compliance, dedicated infrastructure, and a self-hosted or Bring Your Own Cloud deployment option for teams with strict data residency requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Web-based admin interface$q$, $q$Files and folders can be uploaded and managed directly through a browser-based admin panel.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Command-line upload tool$q$, $q$A CLI tool lets users push files from a local folder to the server, useful for scripted or automated deployments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$WebDAV support$q$, $q$Surfer exposes a WebDAV endpoint so it can be mounted as a network drive in desktop file managers on Windows, Mac, and Linux.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Automatic index file serving$q$, $q$The server automatically serves index.html or index.htm for a directory, matching standard static site behavior.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Optional directory listing$q$, $q$Folders without an index file can optionally show a public listing of their contents.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Custom error pages$q$, $q$A custom 404.html page can be configured to handle requests for missing files or pages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Flexible access control$q$, $q$Each instance can be set to fully public access, password protection, or restricted to logged-in Cloudron users.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Low resource footprint$q$, $q$Surfer is lightweight enough that running one instance per domain for isolation is a practical, low-overhead pattern.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Free and open source with no licensing cost beyond existing Cloudron hosting$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Multiple file management options, including web UI, CLI, and WebDAV$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Very low resource footprint makes it practical to run per-domain instances$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Simple to deploy for anyone already running a Cloudron server$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Flexible access control ranging from public to password-protected to login-restricted$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Requires an existing Cloudron installation, so it is not usable as a standalone hosted product$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Very limited public documentation on founding history, company backing, or roadmap$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Lacks the advanced build tooling, CDN, and deployment automation of dedicated static hosting platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Small niche user base compared to mainstream static hosting services$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Frequently confused with the unrelated Surfer SEO product due to the identical short name$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$What is Surfer on Cloudron$q$, $q$Surfer is a free, open-source static file server app for the Cloudron self-hosting platform, used to host static websites and share files.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Is Surfer related to Surfer SEO$q$, $q$No, Surfer the Cloudron app is completely unrelated to Surfer SEO, a separate content optimization SaaS company; they only share a similar short name.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$How much does Surfer cost$q$, $q$Surfer itself is free and open source; users only pay for the Cloudron server infrastructure it runs on.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$How do I upload files to Surfer$q$, $q$Files can be uploaded through the web-based admin interface, a command-line tool, or a WebDAV connection mounted in a desktop file manager.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Does Surfer support password-protected sites$q$, $q$Yes, each Surfer instance can be configured for public access, password protection, or restricted to logged-in Cloudron users.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Can Surfer host multiple websites$q$, $q$Surfer is designed to be lightweight enough that the recommended approach is running one instance per domain, keeping each site isolated.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Who develops Surfer$q$, $q$Surfer is maintained as part of the Cloudron project in its GitLab and GitHub repositories rather than by a separate standalone company.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Does Surfer support custom error pages$q$, $q$Yes, Surfer supports a custom 404.html page for handling requests to missing files or pages.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Static website hosting$q$, $q$Self-hosters deploy Surfer on their Cloudron server to serve a static website built with any static site generator.$q$, $q$Self-hosting individuals and small teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Private file sharing$q$, $q$Teams use Surfer's WebDAV and web interface to share and manage files on their own infrastructure instead of a third-party cloud storage service.$q$, $q$Privacy-conscious teams and individuals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Simple CI deployment target$q$, $q$Developers use the Surfer command-line tool to push build output from a continuous integration pipeline directly to a self-hosted static site.$q$, $q$Developers running self-hosted infrastructure$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$Open Source (self-hosted via Cloudron)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Web-based admin interface","Command-line upload tool","WebDAV file access","Custom error pages","Public, password-protected, or login-restricted access modes"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$overview$q$, $q$What Is Surfer$q$, 2, ARRAY[$q$Surfer is a simple, open-source static file server distributed as a packaged app for Cloudron, a self-hosting platform for running web applications on your own server. It is maintained in Cloudron's own GitLab and GitHub repositories rather than by a standalone commercial company.$q$, $q$This Surfer should not be confused with Surfer SEO, a separate and unrelated content optimization SaaS company based in Poland. The Cloudron Surfer app has no connection to Surfer SEO's product, team, pricing, or business, and the two only happen to share a short product name.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Surfer is designed for hosting static websites and sharing files from a self-hosted Cloudron instance. Files can be managed three ways: through a web-based admin interface, a command-line tool that uploads files from local folders, or a WebDAV endpoint that lets a desktop file manager mount the server as a network drive.$q$, $q$The app automatically serves an index.html or index.htm file for a given directory, can optionally show a directory listing for folders without an index file, and supports a custom 404.html page for handling missing pages. Access to each Surfer instance can be configured as fully public, password protected, or restricted to logged-in Cloudron users, and its command-line tool supports scripted deployment for basic continuous integration workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Surfer is free and open source. Since it runs as an app inside a self-hosted Cloudron installation, there is no separate license fee for the Surfer package itself; the only cost is whatever a user already pays for their Cloudron server and hosting infrastructure.$q$, $q$There are no paid tiers, add-ons, or usage-based charges specific to Surfer, which is consistent with its role as a lightweight utility app in the broader Cloudron app store rather than a standalone commercial product.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7790e8ea-c240-4ee6-9b40-8da31a143d62', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$SERP-based content editor$q$, $q$Drafts are scored against real-time data from top-ranking pages, with guidance on word count, headings, and keyword usage.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Keyword research$q$, $q$Built-in keyword research tools help identify target terms and related topics to cover in content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$AI search visibility tracking$q$, $q$Tracks how content and brand mentions appear across AI answer engines including ChatGPT, Perplexity, Google AI features, and Gemini.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Content audit$q$, $q$Existing pages can be audited and re-optimized against current SERP data to improve rankings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Topical mapping$q$, $q$Helps teams plan clusters of related content around a core topic to build topical authority.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Internal linking and cannibalization reports$q$, $q$Identifies internal linking opportunities and flags pages competing for the same keywords.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Plagiarism checker and AI humanizer$q$, $q$Built-in checks help ensure originality and reduce AI-sounding phrasing in generated drafts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$CMS and workflow integrations$q$, $q$Native integrations with WordPress, Google Docs, Contentful, and Zapier fit Surfer into existing publishing workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Quantitative, data-driven content guidelines based on real top-ranking search results$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Expanded AI search visibility tracking keeps pace with the shift toward AI answer engines$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Wide range of features spanning research, writing, auditing, and internal linking in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Native integrations with popular CMS and workflow tools like WordPress and Google Docs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$7-day money-back guarantee on every plan reduces the risk of trying it$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Entry-level Discovery plan has a fairly limited document allowance for active content teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Higher tiers needed for daily AI prompt tracking and multi-AI coverage can get expensive$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Content scores can encourage keyword-driven writing that some teams find overly formulaic$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Recently acquired by Groupe Positive, adding some uncertainty around long-term branding and roadmap changes$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Enterprise-grade features like SSO and white-labeling require the highest, custom-priced tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$What is Surfer SEO used for$q$, $q$Surfer SEO is used to optimize written content for search rankings by scoring drafts against data from top-ranking pages and providing keyword, structure, and internal linking guidance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$How much does Surfer SEO cost$q$, $q$As of 2026, plans range from 49 euros per month for Discovery to 299 euros per month for Peace of Mind, with a custom-priced Enterprise tier starting around 999 euros per month, all billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Who founded Surfer SEO$q$, $q$Surfer SEO was founded in 2017 by Michal Suski and Tomasz Niezgoda in Wroclaw, Poland.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Was Surfer SEO acquired$q$, $q$Yes, Surfer SEO was acquired by Groupe Positive, a European SaaS provider based in Lille, France, in January 2025.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Does Surfer SEO track AI search results$q$, $q$Yes, higher-tier plans track brand and content visibility across AI answer engines including ChatGPT, Perplexity, Google AI features, and Gemini.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Does Surfer SEO integrate with WordPress$q$, $q$Yes, Surfer SEO offers native integrations with WordPress, Google Docs, Contentful, and Zapier.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Is Surfer SEO the same as the Cloudron app called Surfer$q$, $q$No, Surfer SEO is a completely separate and unrelated product from the Cloudron Surfer static file server; they only share a similar short name.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Does Surfer SEO offer a free trial or refund$q$, $q$Surfer SEO does not typically offer a free plan, but every paid plan includes a 7-day money-back guarantee.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$SEO content briefs and optimization$q$, $q$Content teams use Surfer SEO to generate data-driven briefs and score drafts before publishing to improve organic ranking potential.$q$, $q$Content marketers and SEO specialists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Agency content production at scale$q$, $q$SEO agencies use Surfer SEO across multiple client accounts to standardize content optimization workflows and reporting.$q$, $q$Digital marketing and SEO agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$AI search visibility monitoring$q$, $q$Brands track how their content and mentions appear in AI answer engines to adapt content strategy for AI-driven search.$q$, $q$In-house SEO and brand marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Discovery$q$, $q$49 euros/month billed annually$q$, $q$annual$q$, NULL, $q$["120 documents","Track 10 pages","AI SEO optimization guidelines","Basic AI assistant (Surfy)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Standard$q$, $q$99 euros/month billed annually$q$, $q$annual$q$, NULL, $q$["360 documents","Track 25 AI prompts with weekly refresh","ChatGPT tracking","Brand knowledge and one-click optimization","Team collaboration features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Pro$q$, $q$182 euros/month billed annually$q$, $q$annual$q$, NULL, $q$["360 documents","Track 50 AI prompts with daily refresh","Multi-AI tracking across ChatGPT, Perplexity, Google, and Gemini","5 brand workspaces","Internal linking and content gap analysis","Cannibalization reports"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Peace of Mind$q$, $q$299 euros/month billed annually$q$, $q$annual$q$, NULL, $q$["Unlimited documents","Track 100 AI prompts with daily refresh","All AI model tracking","Unlimited brand workspaces","Advanced SERP analysis","Dedicated success manager","API access"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Enterprise$q$, $q$From 999 euros/month, custom pricing$q$, $q$annual$q$, NULL, $q$["Custom limits","White-label options","SSO and enterprise-grade security","Advisory program"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$overview$q$, $q$What Is Surfer SEO$q$, 2, ARRAY[$q$Surfer SEO is a cloud-based content optimization platform founded in 2017 by Michal Suski and Tomasz Niezgoda in Wroclaw, Poland. It started as a tool for analyzing top-ranking search results and has grown into a broader AI-driven content optimization suite used by more than 150,000 content creators, SEO professionals, and marketing agencies.$q$, $q$In January 2025, Surfer SEO was acquired by Groupe Positive, a European SaaS provider headquartered in Lille, France, and the product is now also marketed under the name Positive Surfer while retaining the Surfer SEO brand for its core content optimization tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of Surfer SEO is its content editor, which scores a draft against data pulled from top-ranking pages for a target keyword and gives quantitative guidelines on word count, headings, keyword usage, and related terms. It also includes keyword research, topical mapping, content gap and cannibalization analysis, and an internal linking tool.$q$, $q$More recently, Surfer SEO has expanded into AI search visibility, tracking how a brand and its content appear in AI answer engines like ChatGPT, Perplexity, Google AI features, and Gemini. Other features include a plagiarism checker, an AI humanizer, an AI writing assistant called Surfy, and native integrations with WordPress, Google Docs, Contentful, and Zapier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Surfer SEO is sold on five annually-billed tiers. Discovery starts at 49 euros per month with 120 documents and tracking for 10 pages. Standard is 99 euros per month with 360 documents and weekly-refreshed AI prompt tracking. Pro is 182 euros per month, the most commonly recommended tier, with daily-refreshed multi-AI tracking across ChatGPT, Perplexity, Google, and Gemini, plus internal linking and content gap analysis.$q$, $q$The Peace of Mind plan is 299 euros per month with unlimited documents, 100 tracked AI prompts refreshed daily, advanced SERP analysis, a dedicated success manager, and API access. Enterprise starts around 999 euros per month with custom limits, white-label options, SSO, and an advisory program. Every plan includes a 7-day money-back guarantee.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Unlimited device connections$q$, $q$Every plan allows unlimited simultaneous device connections, unlike many competing VPN services that cap device counts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Large server network$q$, $q$More than 4,500 servers across roughly 100 countries support fast, geographically diverse connections.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Ad and cookie pop-up blocker$q$, $q$Built-in blocking reduces ads and cookie consent pop-ups while browsing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Double VPN encryption$q$, $q$Traffic can be routed through two servers for an additional layer of encryption.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Independently audited no-logs policy$q$, $q$Surfshark's claim of not logging user activity has been verified through independent audits.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Antivirus suite (Surfshark One)$q$, $q$Real-time antivirus protection is bundled into the Surfshark One and One+ tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Identity and data breach monitoring$q$, $q$Surfshark Alert on the One+ tier monitors for data breaches involving a user's personal information.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Data removal service$q$, $q$The Incogni integration on One+ helps remove personal data from data broker sites.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Unlimited simultaneous device connections on every plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Large server network spanning roughly 100 countries$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Independently audited no-logs privacy policy$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Bundled antivirus and identity protection options for users who want more than just a VPN$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$30-day money-back guarantee lowers the risk of trying the service$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Lowest advertised prices require committing to a 24-month plan; monthly pricing is significantly higher$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Antivirus and identity protection add-ons raise the price compared to VPN-only competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Merger with Nord Security in 2022 has raised some user questions about long-term brand independence$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Some advanced privacy features like identity theft coverage are limited to United States residents$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Promotional pricing structures with bonus months can make true cost comparisons harder for new customers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$What is Surfshark used for$q$, $q$Surfshark is a VPN service used to encrypt internet traffic, mask a user's IP address, and add privacy tools like ad blocking, antivirus, and identity monitoring.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$How much does Surfshark cost$q$, $q$The Starter plan starts around 2.29 euros per month on the long-term two-year plan, with Surfshark One and One+ priced higher for added antivirus and identity protection features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Is Surfshark owned by Nord Security$q$, $q$Surfshark merged with Nord Security in 2022, but the two continue to operate as separate products with independent apps, infrastructure, and pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Does Surfshark allow unlimited devices$q$, $q$Yes, every Surfshark plan supports unlimited simultaneous device connections.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Where is Surfshark headquartered$q$, $q$Surfshark is headquartered in Amsterdam, Netherlands, with additional offices in Lithuania, Poland, and Germany.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Does Surfshark keep logs of user activity$q$, $q$No, Surfshark operates under a no-logs policy that has been independently audited.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$What is the difference between Surfshark Starter, One, and One+$q$, $q$Starter includes core VPN features and ad blocking, One adds an antivirus suite, and One+ adds Surfshark Alert identity monitoring and Incogni data removal.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Does Surfshark offer a money-back guarantee$q$, $q$Yes, all Surfshark plans include a 30-day money-back guarantee.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Household-wide VPN coverage$q$, $q$Families use Surfshark's unlimited device connections to secure every phone, laptop, and smart TV in a household under a single subscription.$q$, $q$Individuals and families$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Public Wi-Fi security$q$, $q$Travelers and remote workers use Surfshark to encrypt traffic and protect data when connecting through public or untrusted Wi-Fi networks.$q$, $q$Travelers and remote workers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Bundled privacy protection$q$, $q$Privacy-conscious users choose Surfshark One or One+ to combine VPN, antivirus, and identity monitoring in a single subscription instead of buying separate tools.$q$, $q$Privacy and security-conscious consumers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Starter$q$, $q$From 2.29 euros/month (2-year plan plus bonus months)$q$, $q$monthly, annual, or 2-year$q$, NULL, $q$["Full VPN access","4,500-plus servers in about 100 countries","Unlimited device connections","Ad and cookie pop-up blocker","Double VPN"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Surfshark One$q$, $q$From 2.79 euros/month (2-year plan plus bonus months)$q$, $q$monthly, annual, or 2-year$q$, NULL, $q$["Everything in Starter","Antivirus with real-time protection","Alternative ID (masked email, persona generator)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$Surfshark One+$q$, $q$From 4.49 euros/month (2-year plan plus bonus months)$q$, $q$monthly, annual, or 2-year$q$, NULL, $q$["Everything in Surfshark One","Surfshark Alert data breach monitoring","Identity theft coverage up to 1 million dollars for US residents","Incogni data removal service"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$overview$q$, $q$What Is Surfshark$q$, 2, ARRAY[$q$Surfshark is a consumer VPN and digital privacy service founded in 2018 and headquartered in Amsterdam, Netherlands, with additional offices in Lithuania, Poland, and Germany. In 2022 the company merged with Nord Security, though Surfshark continues to operate as an independent product with its own apps, server network, and pricing.$q$, $q$Surfshark differentiates itself from many VPN competitors by allowing unlimited simultaneous device connections on every subscription, making a single plan usable across an entire household or every device an individual owns.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core VPN service includes strong encryption and IP masking across a network of more than 4,500 servers in roughly 100 countries, along with an ad and cookie pop-up blocker, rotating IP addresses, and a double VPN mode that routes traffic through two servers for additional encryption. Surfshark's no-logs policy has been independently audited.$q$, $q$Beyond the VPN itself, Surfshark bundles optional privacy tools into its higher tiers, including Surfshark Alternative ID for masked emails and generated personas, an antivirus suite with real-time protection, Surfshark Alert for data breach monitoring, an ad-free private search tool, and identity theft coverage up to 1 million dollars for United States residents, along with the Incogni data removal service.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99717d1e-0342-4761-94f2-a883ec1305b3', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Surfshark offers three subscription tiers: Starter, Surfshark One, and Surfshark One+, each available on monthly, one-year, or two-year billing with the lowest per-month rate on the two-year plan plus bonus months. Starter pricing begins around 2.29 euros per month on the long-term plan and covers full VPN access, ad blocking, and cookie pop-up blocking.$q$, $q$Surfshark One adds a bundled antivirus suite for a modest price increase, while Surfshark One+ adds Surfshark Alert identity protection and Incogni data removal on top of everything in the lower tiers. All plans include a 30-day money-back guarantee, and pricing varies by currency, region, and active promotional discounts.$q$]::text[], 2);
